using Microsoft.AspNetCore.Mvc;
using System.IO;
namespace FileUploaderApp.Controllers
{    
    [Route("api/[controller]")]   // Route Template in ASP.NET Core 3+ MVC Controller Attribute is automatically generated by the Routing mechanism of .net core, you don't need to define it manually here as we are using route template feature provided by asp net core mvc
    [ApiController]              // This attribute will ensure that your controller follows best practices for ASP.NET Core MVC and C# 6/7 features (like the new `[ApiController]` attribute). It's a part of .net standard library, so you don’t need to install it separately
    public class FileUploaderController : ControllerBase   // This is where we inherit from our base controller. ASP.NET Core MVC uses this for us and provides the functionality that makes up an HTTP request/response pipeline in a web application by handling requests, responses (including file uploads), sessions etc...
    {        
        [HttpGet("{filename}")]   // This is where we define our route template which will be used to access methods of this controller. The `[FromRoute]` attribute bind the parameter from URL into method's parameters automatically, and also it provides a way for client applications (like browser) or other services like REST clients that can use HTTP/1.0 GET requests with query strings in their URI structure
        public IActionResult GetFile(string filename)   // This is where we define our action which will handle the file uploads and serve them to users, it takes a `filename` parameter from URL route template 
        {        
            var path = Path.Combine("uploads", filename);    // Combines two strings into one string using '\' as separator (Path class in .NET Core) which is the directory of upload files and file name provided by user, then it will create a full absolute or relative paths to that uploaded document
            
            if (!System.IO.File.Exists(path))   // If there's no such path exists on server – return not found status code (404) with message "file does not exist" and file name as parameter in JSON format, because client may have wrong filename or it might be deleted by user
            {        
                return NotFound("File does not exist");   // This will automatically generate a response body containing the error details. The status code is set to 404 (Not Found) and content type as 'application/json' which means that this method returns JSON data in HTTP responses, so it can be consumed by JavaScript clients
            }        
            
            var fileContents = System.IO.File.ReadAllBytes(path);   // Reads all bytes from the specified path into a byte array and then sends back to client as response body with appropriate content type (application/octet-stream in this case) – it'll return document contents for user
            
            var mimType = MimeTypes.GetMimeType(Path.GetExtension(filename));   // Get the mimetype of file using extension from filename, if there is no such type then default to 'application/octet-stream'. It will be used as content type in response body – it's a part that client can understand and handle
            
            return File(fileContents, mimType);   // This sends the bytes of file contents into HTTP Response with appropriate mime (content)type. The `File` method is an extension from ASP .NET Core to send files in response body – it's a part that client can understand and handle
        }        
    }    
}